543	      // Save to log
544	      saveDifficulty(key, exercise, difficulty);
545	    }
546	  });
547	
548	  // Failed sliders (delegated)
549	  document.getElementById('exercises-list').addEventListener('input', (e) => {
550	    if (e.target.classList.contains('failed-set-slider') || e.target.classList.contains('failed-rep-slider')) {
551	      const slider = e.target;
552	      const key = slider.dataset.key;
553	      const exercise = slider.dataset.exercise;
554	
555	      // Update display value
556	      const label = slider.previousElementSibling;
557	      label.querySelector('.slider-value').textContent = slider.value;
558	
559	      // Save to log
560	      saveFailedDetails(key, exercise);
561	    }
562	  });
563	
564	  // Notes field (delegated)
565	  document.getElementById('exercises-list').addEventListener('input', (e) => {
566	    if (e.target.classList.contains('notes-field')) {
567	      saveNotes(e.target);
568	    }
569	  });
570	
571	  // Done button (delegated)
572	  document.getElementById('exercises-list').addEventListener('click', (e) => {
573	    if (e.target.classList.contains('done-btn')) {
574	      const btn = e.target;
575	      const key = btn.dataset.key;
576	      const exercise = btn.dataset.exercise;
577	      const exerciseCard = btn.closest('.exercise');
578	      const section = btn.closest('.feedback-section');
579	      const log = loadLog();
580	
581	      const wasCompleted = log[key] && log[key].completed;
582	
583	      if (!wasCompleted) {
584	        // Mark as completed, expand feedback
585	        log[key] = {
586	          ...log[key],
587	          exercise: exercise,
588	          completed: true,
589	          day: currentState.globalDay,
590	          timestamp: Date.now()
591	        };
592	        btn.classList.add('is-done');
593	        btn.innerHTML = '\u2713 DONE';
594	        exerciseCard.classList.add('completed');
595	        section.classList.add('expanded');
596	      } else {
597	        // Undo completion
598	        delete log[key].completed;
599	        // If no meaningful data left, remove the entry
600	        if (!log[key].weight && !log[key].difficulty && !log[key].notes) {
601	          delete log[key];
602	        }
603	        btn.classList.remove('is-done');
604	        btn.innerHTML = 'DONE';
605	        exerciseCard.classList.remove('completed');
606	        section.classList.remove('expanded');
607	      }
608	
609	      saveLog(log);
610	      updateProgressBar();
611	    }
612	  });
613	}
614	
615	// Save weight input to log
616	function saveWeightInput(input) {
617	  const log = loadLog();
618	  const key = input.dataset.key;
619	  const weight = input.value;
620	
621	  const parsedWeight = parseFloat(weight);
622	  if (weight && !isNaN(parsedWeight)) {
623	    // Preserve existing fields when updating weight
624	    log[key] = {
625	      ...log[key],
626	      exercise: input.dataset.exercise,
627	      weight: parsedWeight,
628	      day: currentState.globalDay,
629	      timestamp: Date.now()
630	    };
631	  } else if (log[key]) {
632	    // Remove weight but keep other fields if they exist
633	    delete log[key].weight;
634	    // If no meaningful data left, remove the entry
635	    if (!log[key].difficulty && !log[key].notes) {
636	      delete log[key];
637	    }
638	  }
639	
640	  saveLog(log);
641	}
