659	  }
660	
661	  saveLog(log);
662	}
663	
664	// Save failed set/rep details to log
665	function saveFailedDetails(key, exercise) {
666	  const log = loadLog();
667	  const setSlider = document.querySelector(`.failed-set-slider[data-key="${key}"]`);
668	  const repSlider = document.querySelector(`.failed-rep-slider[data-key="${key}"]`);
669	
