672	    exercise: exercise,
673	    failedSet: parseInt(setSlider.value),
674	    failedRep: parseInt(repSlider.value),
675	    day: currentState.globalDay,
676	    timestamp: Date.now()
677	  };
678	
679	  saveLog(log);
680	}
681	
682	// Save notes to log
683	function saveNotes(textarea) {
684	  const log = loadLog();
685	  const key = textarea.dataset.key;
686	  const notes = textarea.value.trim();
687	
688	  if (notes || log[key]) {
689	    log[key] = {
690	      ...log[key],
691	      exercise: textarea.dataset.exercise,
692	      notes: notes,
693	      day: currentState.globalDay,
694	      timestamp: Date.now()
695	    };
696	
697	    // Clean up empty notes
698	    if (!notes) {
699	      delete log[key].notes;
700	    }
701	
702	    // If no meaningful data left, remove the entry
703	    if (!log[key].weight && !log[key].difficulty && !log[key].notes) {
704	      delete log[key];
705	    }
706	  }
707	
708	  saveLog(log);
709	}
