711	// Complete workout and advance day
712	function completeWorkout() {
713	  if (currentState.globalDay >= 365) {
714	    alert('Congratulations! You completed the 365-day program!');
715	    return;
716	  }
717	
718	  currentState.globalDay++;
719	
720	  // Check for phase transition (simplified - would need more logic for real phases)
721	  const phase = getCurrentPhase();
722	  if (phase) {
723	    const daysInPhase = phase.duration_weeks * 7;
724	    if (currentState.globalDay > daysInPhase && programData.phases.length > 1) {
725	      const currentIndex = programData.phases.findIndex(p => p.id === currentState.currentPhase);
726	      if (currentIndex < programData.phases.length - 1) {
727	        currentState.currentPhase = programData.phases[currentIndex + 1].id;
728	      }
729	    }
730	  }
731	
732	  saveState();
733	  render();
734	
735	  // Scroll to top
736	  window.scrollTo({ top: 0, behavior: 'smooth' });
737	}
