739	// Go back one day
740	function goBack() {
741	  if (currentState.globalDay <= 1) return;
742	
743	  currentState.globalDay--;
744	
745	  // Check for phase transition in reverse
746	  const phase = getCurrentPhase();
747	  if (phase) {
748	    const currentIndex = programData.phases.findIndex(p => p.id === currentState.currentPhase);
749	    if (currentIndex > 0) {
750	      const prevPhase = programData.phases[currentIndex - 1];
751	      const prevPhaseDays = prevPhase.duration_weeks * 7;
752	      if (currentState.globalDay <= prevPhaseDays) {
753	        currentState.currentPhase = prevPhase.id;
754	      }
755	    }
756	  }
757	
758	  saveState();
759	  render();
760	  window.scrollTo({ top: 0, behavior: 'smooth' });
761	}
