803	  const log = loadLog();
804	  const state = JSON.parse(localStorage.getItem(STATE_KEY) || '{}');
805	  const data = { log: log, state: state };
806	  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
807	  const url = URL.createObjectURL(blob);
808	  const a = document.createElement('a');
809	  const today = new Date().toISOString().slice(0, 10);
810	  a.href = url;
811	  a.download = `flux-backup-${today}.json`;
812	  document.body.appendChild(a);
813	  a.click();
814	  document.body.removeChild(a);
