818	// Sanitize a log entry to only include expected fields with safe types
819	function sanitizeLogEntry(entry) {
820	  if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return {};
821	  const sanitized = {};
822	  if (typeof entry.weight === 'number' || typeof entry.weight === 'string') {
823	    sanitized.weight = String(entry.weight).slice(0, 20);
824	  }
825	  if (typeof entry.difficulty === 'string' && ['easy', 'good', 'hard', 'failed'].includes(entry.difficulty)) {
826	    sanitized.difficulty = entry.difficulty;
827	  }
828	  if (typeof entry.notes === 'string') {
829	    sanitized.notes = entry.notes.slice(0, 500);
830	  }
831	  if (typeof entry.exercise === 'string') {
832	    sanitized.exercise = entry.exercise.slice(0, 200);
833	  }
834	  if (typeof entry.completed === 'boolean') {
835	    sanitized.completed = entry.completed;
836	  }
837	  if (typeof entry.day === 'number' && Number.isFinite(entry.day)) {
838	    sanitized.day = entry.day;
839	  }
840	  if (typeof entry.timestamp === 'number' && Number.isFinite(entry.timestamp)) {
841	    sanitized.timestamp = entry.timestamp;
842	  }
843	  if (typeof entry.failedSet === 'number' && Number.isFinite(entry.failedSet)) {
844	    sanitized.failedSet = entry.failedSet;
845	  }
846	  if (typeof entry.failedRep === 'number' && Number.isFinite(entry.failedRep)) {
847	    sanitized.failedRep = entry.failedRep;
848	  }
849	  return sanitized;
850	}
