854	  const reader = new FileReader();
855	  reader.onload = function(e) {
856	    try {
857	      const data = JSON.parse(e.target.result);
858	      if (!data.log || typeof data.log !== 'object' || Array.isArray(data.log)) {
859	        alert('Invalid backup file: missing or malformed log data.');
860	        return;
861	      }
862	
863	      const importEntries = Object.keys(data.log);
864	      const count = importEntries.length;
865	      if (count === 0) {
866	        alert('No workout entries found in backup file.');
867	        return;
868	      }
869	
870	      if (!confirm(`Import ${count} workout ${count === 1 ? 'entry' : 'entries'}? This will merge with existing data.`)) {
871	        return;
872	      }
873	
874	      const existingLog = loadLog();
875	      let imported = 0;
876	      for (const key of importEntries) {
877	        if (!existingLog[key]) {
878	          existingLog[key] = sanitizeLogEntry(data.log[key]);
879	          imported++;
880	        }
881	      }
882	
883	      saveLog(existingLog);
884	      render();
885	      alert(`Imported ${imported} new ${imported === 1 ? 'entry' : 'entries'}. ${count - imported} already existed.`);
886	    } catch (err) {
887	      alert('Error reading backup file: ' + err.message);
888	    }
889	  };
890	  reader.readAsText(file);
891	}
