                    : 'border-flux-border bg-flux-soft text-flux-text-secondary hover:text-flux-text-primary')
                }
                onClick={() => setDifficulty(d)}
                data-testid={`difficulty-${index}-${d}`}
              >
                {d.toUpperCase()}
